const express = require('express');
const axios = require('axios');

const app = express();
const PORT = process.env.PORT || 3000;

// Middleware to parse JSON request bodies
app.use(express.json());

// Exponential backoff retry function
async function callPremblyAPI(nin) {
  const baseURL = process.env.PREMBLY_BASE_URL || 'https://api.prembly.com';
  const path = '/verification/nin';
  const url = `${baseURL}${path}`;

  const headers = {
    'app-id': process.env.PREMBLY_APP_ID,
    'x-api-key': process.env.PREMBLY_API_KEY
  };

  const data = { nin };

  const maxRetries = 3;
  const retryDelays = [100, 200, 400]; // 100ms, 200ms, 400ms

  for (let attempt = 0; attempt <= maxRetries; attempt++) {
    try {
      const response = await axios.post(url, data, { headers });

      // If successful, return the response
      return response.data;
    } catch (error) {
      // Check if it's a 429 rate limit error
      if (error.response && error.response.status === 429) {
        // If we've exhausted all retries, throw the error
        if (attempt === maxRetries) {
          throw error;
        }

        // Wait for the specified delay before retrying
        const delay = retryDelays[attempt];
        await new Promise(resolve => setTimeout(resolve, delay));
      } else {
        // For other errors, throw immediately
        throw error;
      }
    }
  }
}

// POST /verify-nin endpoint
app.post('/verify-nin', async (req, res) => {
  try {
    const { nin } = req.body;

    // Validate that nin is provided
    if (!nin) {
      return res.status(400).json({ error: 'NIN is required' });
    }

    // Call Prembly API with retry logic
    const result = await callPremblyAPI(nin);

    // Return successful response
    return res.status(200).json(result);
  } catch (error) {
    // Check if it's a rate limit error
    if (error.response && error.response.status === 429) {
      return res.status(429).json({ 
        message: 'Rate limit exceeded, please try again later' 
      });
    }

    // For other errors, return 500
    console.error('Error verifying NIN:', error.message);
    return res.status(500).json({ 
      error: 'An error occurred while verifying NIN' 
    });
  }
});

// Start the server
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

